    popupAdItem: null,
    popupAdVisible: false,
    isProUser: false,
    pageDesc: 'SpaceX星舰Starship建造进度·马斯克火箭回收OpenClaw猎鹰9号航天太空追踪',
    statusBarHeight: 44,
    navPlaceholderHeight: 0,
    tabBarReservedHeight: 0,
